import{_ as a,o as i,c as s,ag as r}from"./chunks/framework.DGzMGr_a.js";const c=JSON.parse('{"title":"六西格玛（Six Sigma）","description":"","frontmatter":{},"headers":[],"relativePath":"standards/six-sigma.md","filePath":"standards/six-sigma.md","lastUpdated":null}'),e={name:"standards/six-sigma.md"};function l(d,t,n,o,h,p){return i(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="六西格玛-six-sigma" tabindex="-1">六西格玛（Six Sigma） <a class="header-anchor" href="#六西格玛-six-sigma" aria-label="Permalink to &quot;六西格玛（Six Sigma）&quot;">​</a></h1><p>六西格玛是一套系统化的质量管理方法论，旨在通过减少过程变异和缺陷来提升质量。它由摩托罗拉（Motorola）在 1986 年提出，后被通用电气（GE）等企业广泛应用。</p><h2 id="六西格玛的统计学含义" tabindex="-1">六西格玛的统计学含义 <a class="header-anchor" href="#六西格玛的统计学含义" aria-label="Permalink to &quot;六西格玛的统计学含义&quot;">​</a></h2><h3 id="什么是-西格玛" tabindex="-1">什么是&quot;西格玛&quot;？ <a class="header-anchor" href="#什么是-西格玛" aria-label="Permalink to &quot;什么是&quot;西格玛&quot;？&quot;">​</a></h3><p>西格玛（σ）是统计学中的标准差，衡量过程的变异程度。<strong>六西格玛</strong>意味着过程的波动极小，使得规格限内包含了 ±6 个标准差的区间。</p><h3 id="_3-4-dpmo-的由来" tabindex="-1">3.4 DPMO 的由来 <a class="header-anchor" href="#_3-4-dpmo-的由来" aria-label="Permalink to &quot;3.4 DPMO 的由来&quot;">​</a></h3><p>在考虑过程偏移（通常取 ±1.5σ 偏移）后：</p><table tabindex="0"><thead><tr><th>西格玛水平</th><th>DPMO（每百万机会缺陷数）</th><th>良率</th></tr></thead><tbody><tr><td>1σ</td><td>697,672</td><td>30.23%</td></tr><tr><td>2σ</td><td>308,770</td><td>69.13%</td></tr><tr><td>3σ</td><td>66,807</td><td>93.32%</td></tr><tr><td>4σ</td><td>6,210</td><td>99.38%</td></tr><tr><td><strong>5σ</strong></td><td><strong>233</strong></td><td><strong>99.977%</strong></td></tr><tr><td><strong>6σ</strong></td><td><strong>3.4</strong></td><td><strong>99.99966%</strong></td></tr></tbody></table><blockquote><p><strong>六西格玛 = 3.4 DPMO</strong>，即每百万次机会中仅有 3.4 个缺陷，良率高达 99.99966%。</p></blockquote><h3 id="计算公式" tabindex="-1">计算公式 <a class="header-anchor" href="#计算公式" aria-label="Permalink to &quot;计算公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DPMO = (缺陷数 ÷ (产品数 × 每产品机会数)) × 1,000,000</span></span></code></pre></div><h3 id="西格玛水平-vs-合格率" tabindex="-1">西格玛水平 vs 合格率 <a class="header-anchor" href="#西格玛水平-vs-合格率" aria-label="Permalink to &quot;西格玛水平 vs 合格率&quot;">​</a></h3><p>西格玛水平与合格率的关系（考虑 1.5σ 偏移）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Z_bench = Z_st + 1.5</span></span></code></pre></div><p>其中 Z_st 是短期西格玛水平，Z_bench 是长期（含偏移）的基准水平。</p><h2 id="dmaic-方法论" tabindex="-1">DMAIC 方法论 <a class="header-anchor" href="#dmaic-方法论" aria-label="Permalink to &quot;DMAIC 方法论&quot;">​</a></h2><p>DMAIC 是六西格玛改进项目的核心流程，包含五个阶段：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D[Define&lt;br/&gt;定义] --&gt; M[Measure&lt;br/&gt;测量]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    M --&gt; A[Analyze&lt;br/&gt;分析]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; I[Improve&lt;br/&gt;改进]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; C[Control&lt;br/&gt;控制]</span></span></code></pre></div><h3 id="_1-定义-define" tabindex="-1">1. 定义（Define） <a class="header-anchor" href="#_1-定义-define" aria-label="Permalink to &quot;1. 定义（Define）&quot;">​</a></h3><p><strong>目标</strong>：明确问题、项目目标和顾客需求。</p><p><strong>关键工具</strong>：</p><ul><li>项目章程（Project Charter）</li><li>SIPOC 图（供方-输入-过程-输出-顾客）</li><li>Kano 模型</li><li>CTQ（关键质量特性）树</li></ul><h3 id="_2-测量-measure" tabindex="-1">2. 测量（Measure） <a class="header-anchor" href="#_2-测量-measure" aria-label="Permalink to &quot;2. 测量（Measure）&quot;">​</a></h3><p><strong>目标</strong>：收集当前过程数据，建立基线。</p><p><strong>关键工具</strong>：</p><ul><li>过程流程图</li><li>数据收集计划</li><li>MSA（测量系统分析）</li><li>过程能力分析（CP/CPK）</li></ul><h3 id="_3-分析-analyze" tabindex="-1">3. 分析（Analyze） <a class="header-anchor" href="#_3-分析-analyze" aria-label="Permalink to &quot;3. 分析（Analyze）&quot;">​</a></h3><p><strong>目标</strong>：识别根本原因，验证关键影响因子。</p><p><strong>关键工具</strong>：</p><ul><li>因果图（鱼骨图）</li><li>5 Why 分析法</li><li>假设检验（t 检验、F 检验、卡方检验）</li><li>方差分析（ANOVA）</li><li>回归分析</li><li>FMEA</li></ul><h3 id="_4-改进-improve" tabindex="-1">4. 改进（Improve） <a class="header-anchor" href="#_4-改进-improve" aria-label="Permalink to &quot;4. 改进（Improve）&quot;">​</a></h3><p><strong>目标</strong>：制定和实施改进方案，验证效果。</p><p><strong>关键工具</strong>：</p><ul><li>DOE（实验设计）</li><li>防错（Poka-Yoke）</li><li>标杆分析（Benchmarking）</li><li>方案优先级矩阵</li></ul><h3 id="_5-控制-control" tabindex="-1">5. 控制（Control） <a class="header-anchor" href="#_5-控制-control" aria-label="Permalink to &quot;5. 控制（Control）&quot;">​</a></h3><p><strong>目标</strong>：保持改进成果，实现标准化。</p><p><strong>关键工具</strong>：</p><ul><li>控制图（SPC）</li><li>控制计划（Control Plan）</li><li>标准化作业指导书</li><li>培训与交接</li><li>项目移交报告</li></ul><h3 id="dmaic-各阶段常用工具汇总" tabindex="-1">DMAIC 各阶段常用工具汇总 <a class="header-anchor" href="#dmaic-各阶段常用工具汇总" aria-label="Permalink to &quot;DMAIC 各阶段常用工具汇总&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>关键输出</th><th>常用工具</th></tr></thead><tbody><tr><td>D</td><td>项目章程、SIPOC、CTQ</td><td>头脑风暴、SIPOC、Kano 模型</td></tr><tr><td>M</td><td>基线数据、过程能力报告</td><td>MSA、控制图、CPK 分析</td></tr><tr><td>A</td><td>根本原因列表、假设检验</td><td>鱼骨图、FMEA、回归分析、ANOVA</td></tr><tr><td>I</td><td>改进方案、试点结果</td><td>DOE、防错、FMEA 更新</td></tr><tr><td>C</td><td>控制计划、监控系统</td><td>SPC、控制计划、标准化作业</td></tr></tbody></table><h2 id="dmadv-dfss" tabindex="-1">DMADV / DFSS <a class="header-anchor" href="#dmadv-dfss" aria-label="Permalink to &quot;DMADV / DFSS&quot;">​</a></h2><p>除了 DMAIC，还有面向六西格玛设计（DFSS）的 <strong>DMADV</strong> 方法论：</p><ul><li><strong>D</strong>efine — 定义设计目标</li><li><strong>M</strong>easure — 测量顾客需求</li><li><strong>A</strong>nalyze — 分析设计概念</li><li><strong>D</strong>esign — 设计详细方案</li><li><strong>V</strong>erify — 验证设计性能</li></ul><blockquote><p>选择原则：<strong>DMAIC</strong> 用于改进现有过程，<strong>DMADV/DFSS</strong> 用于设计新产品或新过程。</p></blockquote><h2 id="六西格玛角色体系" tabindex="-1">六西格玛角色体系 <a class="header-anchor" href="#六西格玛角色体系" aria-label="Permalink to &quot;六西格玛角色体系&quot;">​</a></h2><p>六西格玛的推行需要明确的分工与角色体系：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Champion[Champion 倡导者&lt;br/&gt;高层管理者] --&gt; MBB[MBB 黑带大师&lt;br/&gt;方法论专家与教练]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    MBB --&gt; BB[BB 黑带&lt;br/&gt;项目领导者]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    BB --&gt; GB[GB 绿带&lt;br/&gt;项目参与者]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    GB --&gt; YB[YB 黄带&lt;br/&gt;基层支持者]</span></span></code></pre></div><h3 id="各角色职责" tabindex="-1">各角色职责 <a class="header-anchor" href="#各角色职责" aria-label="Permalink to &quot;各角色职责&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>英文</th><th>级别</th><th>典型职责</th></tr></thead><tbody><tr><td><strong>倡导者</strong></td><td>Champion</td><td>高层</td><td>制定战略方向，分配资源，消除障碍，审批项目</td></tr><tr><td><strong>黑带大师</strong></td><td>MBB</td><td>专家级</td><td>培训黑带/绿带，制定方法论标准，指导复杂项目</td></tr><tr><td><strong>黑带</strong></td><td>BB</td><td>高级</td><td>全职领导六西格玛项目，使用高级统计工具</td></tr><tr><td><strong>绿带</strong></td><td>GB</td><td>中级</td><td>兼职参与项目，掌握基本工具，协助黑带</td></tr><tr><td><strong>黄带</strong></td><td>YB</td><td>入门</td><td>了解基本概念，参与数据收集和改善活动</td></tr></tbody></table><h3 id="培训时长参考" tabindex="-1">培训时长参考 <a class="header-anchor" href="#培训时长参考" aria-label="Permalink to &quot;培训时长参考&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>培训时长</th><th>项目要求</th></tr></thead><tbody><tr><td>黄带（YB）</td><td>1–2 天</td><td>不强制要求项目</td></tr><tr><td>绿带（GB）</td><td>10–14 天（分散）</td><td>1 个改进项目</td></tr><tr><td>黑带（BB）</td><td>20–25 天（分散）</td><td>2–3 个复杂项目</td></tr><tr><td>黑带大师（MBB）</td><td>经验积累 + 认证</td><td>指导多个 BB 项目</td></tr></tbody></table><h2 id="六西格玛实施的成功要素" tabindex="-1">六西格玛实施的成功要素 <a class="header-anchor" href="#六西格玛实施的成功要素" aria-label="Permalink to &quot;六西格玛实施的成功要素&quot;">​</a></h2><ol><li><strong>高层领导支持</strong> — Champion 的承诺是项目成功的前提</li><li><strong>数据驱动决策</strong> — 用数据说话，而非凭经验判断</li><li><strong>项目选择恰当</strong> — 项目应与业务目标对齐，范围适当</li><li><strong>团队协作</strong> — 跨部门团队的力量</li><li><strong>持之以恒的文化</strong> — 六西格玛是持续改进的文化变革</li></ol><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./lean-production">精益生产</a></li><li><a href="./">ISO 9001 质量管理体系</a></li><li><a href="/tools/spc">SPC 统计过程控制</a></li><li><a href="/tools/fmea">FMEA 失效模式分析</a></li><li><a href="/certification/six-sigma-belt">六西格玛绿带/黑带认证</a></li><li><a href="/certification/">CQE 认证备考</a></li></ul>`,55)])])}const b=a(e,[["render",l]]);export{c as __pageData,b as default};
